# Core geometry base class

class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"{self.name}: area={self.area()}"

    @virtual
    def get_color(self) -> str:
        return "none"

