# Concrete shape implementations
from geometry import Shape
from utils import Color

class Circle(Shape):
    radius: float
    color_val: Color

    def __init__(self, name: str, radius: float, color: Color):
        super().__init__(name)
        self.radius = radius
        self.color_val = color

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"{self.name} (radius {self.radius}): area={self.area()}"

    @override
    def get_color(self) -> str:
        return f"{self.color_val.name}"

class Rectangle(Shape):
    width: float
    height: float
    color_val: Color

    def __init__(self, name: str, width: float, height: float, color: Color):
        super().__init__(name)
        self.width = width
        self.height = height
        self.color_val = color

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"{self.name} ({self.width} x {self.height}): area={self.area()}"

    @override
    def get_color(self) -> str:
        return f"{self.color_val.name}"
